import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is debt-to-income ratio?", a: "Debt-to-income ratio compares your monthly debt payments to your gross monthly income." },
  { q: "What is a good DTI ratio?", a: "Many lenders prefer back-end DTI below 36%, though some mortgage programs allow higher ratios with strong credit or compensating factors." },
  { q: "What is the difference between front-end and back-end DTI?", a: "Front-end DTI includes housing costs only. Back-end DTI includes housing plus all recurring monthly debts." },
  { q: "How does DTI affect mortgage approval?", a: "DTI helps lenders estimate whether your income can support the new mortgage payment plus existing debts." },
  { q: "How can you improve your DTI ratio?", a: "You can improve DTI by increasing income, reducing monthly debt payments, paying down balances, or choosing a lower housing payment." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function likelihood(backEnd: number) {
  if (backEnd < 28) return "Excellent";
  if (backEnd <= 36) return "Strong";
  if (backEnd <= 43) return "Possible";
  if (backEnd <= 50) return "Difficult";
  return "Unlikely";
}

export default function DebtToIncomeCalculator() {
  useCurrencyVersion();
  const [income, setIncome] = useState(7000);
  const [housing, setHousing] = useState(1800);
  const [car, setCar] = useState(350);
  const [cards, setCards] = useState(150);
  const [student, setStudent] = useState(250);
  const [other, setOther] = useState(100);
  const result = useMemo(() => {
    const totalDebt = housing + car + cards + student + other;
    const front = income ? housing / income * 100 : 0;
    const back = income ? totalDebt / income * 100 : 0;
    return { totalDebt, front, back, likelihood: likelihood(back) };
  }, [income, housing, car, cards, student, other]);
  const rows = [
    ["Under 28%", "Under 28%", "Under 28%", "Conventional", "Excellent"],
    ["28-36%", "28% or less", "36% or less", "Conventional/FHA", "Strong"],
    ["36-43%", "Varies", "43% or less", "FHA/Qualified Mortgage", "Possible"],
    ["43-50%", "Varies", "Up to 50%", "Program dependent", "Difficult"],
    ["Over 50%", "High", "Over 50%", "Limited options", "Unlikely"],
  ];

  return (
    <>
      <SEOHead title="Free Debt-to-Income Ratio Calculator Online - Calculate Your DTI Instantly | CalcHive" description="Free online debt-to-income ratio calculator. Calculate your front-end and back-end DTI ratio and see if you qualify for a mortgage based on lender guidelines instantly. 100% free, no signup required." canonical="/debt-to-income-calculator" keywords="free debt to income ratio calculator, DTI calculator free online, mortgage qualification calculator free, calculate debt to income ratio free, front end back end DTI calculator free" category="Financial Calculators" breadcrumbName="Free Debt-to-Income Ratio Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Debt-to-Income Ratio Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate front-end and back-end DTI and see a mortgage qualification guideline estimate.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            {[["Monthly gross income", income, setIncome], ["Mortgage or rent", housing, setHousing], ["Car loans", car, setCar], ["Credit cards", cards, setCards], ["Student loans", student, setStudent], ["Other debts", other, setOther]].map(([label, value, setter]) => <div key={String(label)}><label className="text-sm font-semibold text-foreground block mb-2">{String(label)}</label><input type="number" value={Number(value)} onChange={(e) => (setter as (v: number) => void)(Number(e.target.value))} className={inputClass} /></div>)}
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Back-End DTI</p><p className="text-5xl sm:text-6xl font-black text-white">{pct(result.back)}</p><p className="text-white/80 mt-2">Approval likelihood: {result.likelihood}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Front-end DTI</p><p className="text-lg font-extrabold text-foreground">{pct(result.front)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Monthly debt</p><p className="text-lg font-extrabold text-foreground">{money(result.totalDebt)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Income</p><p className="text-lg font-extrabold text-foreground">{money(income)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Debt-to-Income Ratio for Free</h2><p className="text-muted-foreground leading-relaxed">Divide monthly debt payments by monthly gross income, then multiply by 100 to get your DTI percentage.</p>
          <h2 className="text-2xl font-bold text-foreground">What DTI Ratio Do Lenders Require for a Mortgage</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">DTI Ratio Mortgage Qualification Guidelines</caption><thead className="bg-muted/60"><tr>{["DTI Ratio", "Front-End", "Back-End", "Loan Type", "Approval Likelihood"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row[0]}>{row.map((cell) => <td key={cell} className="py-2.5 px-3">{cell}</td>)}</tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free DTI Mortgage Qualification Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">This DTI calculator gives a helpful estimate, but final mortgage approval depends on the full loan file and lender rules.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/debt-to-income-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


